    /// <summary>Builds a fresh <see cref="Geometry"/> for the given icon key, or null if unknown.</summary>
    public static Geometry? Get(string? key)
        => key is not null && Paths.TryGetValue(key, out var data)
            ? (Geometry)XamlBindingHelper.ConvertValue(typeof(Geometry), data)
            : null;

    /// <summary>Maps a domain label/id to an icon key, so models never carry a glyph (data, not UI).</summary>
    public static string KeyFor(string? label) => label switch
    {
        // Home quick actions
        "Flights" => "airplane",
        "Hotels" => "bed",
        "Experiences" => "sparkle",
        "Cars" => "car",
        "Trips" => "luggage",
        "Map" => "map",
        // Profile settings
        "Personal Information" => "person",
        "Payment Methods" => "wallet",
        "Notifications" => "alert",
        "Privacy & Security" => "shield",
        "Language" => "language",
        "Currency" => "money",
        "Help & Support" => "help",
        "About Voyago" => "info",
        _ => label ?? "compass",
    };
}
